240	/**
241	 * Select the current conference from the decoded document, matching today's
242	 * `getCurrentConference` semantics exactly (CONTEXT.md §"Current Conference"):
243	 * the first conference whose start date is still in the future, falling back to
244	 * the most recent (last) one.
245	 */
246	const selectCurrent = (
247	  content: SiteContentType,
248	  locale: Locale,
249	  now: number,
250	): Conference => {
251	  const index = content.conferences.findIndex((conference) =>
252	    dayjs(now).isBefore(toEndOfDayMs(conference.dates.start)),
253	  );
254	  const conference =
255	    index === -1 ? content.conferences[content.conferences.length - 1] : content.conferences[index];
256	  if (conference === undefined) {
