262	const selectByYear = (
263	  content: SiteContentType,
264	  locale: Locale,
265	  year: number,
266	): Conference => {
267	  // A Conference is identified by its year `slug` (`/YYYY`, CONTEXT.md
268	  // §"Conference"), which is the canonical year identifier the routes pass and
269	  // the `SiteContent` boundary filter requires to be present. Match on it
270	  // directly rather than re-deriving the year from `dates.start`, so this
271	  // selector and the schema invariant agree (`derive-dont-sync`) and any
272	  // year the routes serve is guaranteed present by the time we get here.
273	  const conference = content.conferences.find(
274	    (candidate) => candidate.slug === `/${year}`,
275	  );
276	  if (conference === undefined) {
277	    throw new Error(`No conference found for year ${year}`);
278	  }
279	  return toConference(conference, locale);
280	};
