311	 */
312	const CACHE_TTL_MS = 30_000;
313	
314	const decodeDocument = Schema.decodeUnknownEffect(Schema.fromJsonString(SiteContent));
315	
316	export class Service extends Context.Service<
317	  Service,
318	  {
319	    readonly getSiteContent: () => Effect.Effect<SiteContentType>;
320	    readonly getConference: (
321	      locale: Locale,
322	      year?: number,
323	    ) => Effect.Effect<Conference>;
324	    readonly getCurrentConference: (
