346	/**
347	 * The `Content` layer (opencode's module-level `export const layer`,
348	 * `packages/core/src/git.ts:79`), leaving its `Storage` requirement open so the
349	 * app runtime and tests can supply different `Storage` layers. `defaultLayer`
350	 * pre-provides `Storage.layerOptional` (the never-fails-to-build storage,
351	 * mirroring `git.ts:347`), leaving only `Env` open — the public read path is
352	 * thus wired with a single `Content.defaultLayer` in the runtime, with `Env`
353	 * discharged by the surrounding merge.
354	 */
355	export const layer = Layer.effect(
356	  Service,
357	  Effect.gen(function* () {
358	    const storage = yield* Storage.Service;
359	
360	    /**
361	     * Read + decode the `SiteContent` document at `key`, or `Option.none()`
362	     * when it is absent / unreadable / malformed. Shared by the public read
363	     * path (which maps `none` to the bundled defaults) and the admin read
364	     * path (which tries the draft, then the published key, then defaults).
365	     */
366	    const readDocument = Effect.fnUntraced(
367	      function* (key: string) {
368	        const object = yield* storage.get(key);
369	        const json = yield* Effect.promise(() =>
370	          new Response(object.stream).text(),
371	        );
372	        return Option.some(yield* decodeDocument(json));
373	      },
374	      (effect, key) =>
375	        effect.pipe(
376	          Effect.catchCause((cause) =>
377	            Effect.logWarning(`Content: could not read ${key}`, cause).pipe(
378	              Effect.as(Option.none<SiteContentType>()),
379	            ),
380	          ),
381	        ),
382	    );
383	
384	    /**
385	     * Read + decode the document from the bucket, falling back to the bundled
386	     * defaults on every failure mode (`boundary-discipline`, D3):
387	     *   - no bucket configured → `Storage.layerOptional` yields a disabled
388	     *     storage whose `get` reports `NotFound`;
389	     *   - object absent / empty → `NotFound`;
390	     *   - bucket unreachable or document malformed → any other failure /
391	     *     decode error / unexpected defect.
392	     * In all cases `readDocument` logs and yields `none`, so the site is never
393	     * broken by a missing or bad document — the public read always gets a
394	     * `SiteContent`.
395	     */
396	    const fetchDocument: Effect.Effect<SiteContentType> = readDocument(
397	      SITE_CONTENT_KEY,
398	    ).pipe(
399	      Effect.map((document) =>
400	        Option.getOrElse(document, () => defaultContent),
401	      ),
402	    );
403	
404	    /**
405	     * The public read cache: Effect's built-in TTL cache with manual
406	     * invalidation (`use-the-platform`). `cachedContent` single-flights
407	     * concurrent first-reads onto one `fetchDocument` (the others park on its
408	     * latch and share the result, so the bucket is not stampeded) and returns
409	     * the same decoded `SiteContent` reference for the TTL's duration;
410	     * `invalidate` arms the next read to re-fetch (the editor's publish path).
411	     */
412	    const [cachedContent, invalidate] = yield* Effect.cachedInvalidateWithTTL(
413	      fetchDocument,
414	      Duration.millis(CACHE_TTL_MS),
415	    );
416	
417	    const getSiteContent = Effect.fn('Content.getSiteContent')(function* () {
418	      return yield* cachedContent;
419	    });
420	
421	    const getConference = Effect.fn('Content.getConference')(function* (
422	      locale: Locale,
423	      year?: number,
424	    ) {
425	      assertValidLocale(locale);
426	      const content = yield* getSiteContent();
427	      const now = yield* Clock.currentTimeMillis;
428	      return year === undefined
429	        ? selectCurrent(content, locale, now)
430	        : selectByYear(content, locale, year);
431	    });
432	
433	    const getCurrentConference = Effect.fn('Content.getCurrentConference')(
434	      function* (locale: Locale) {
435	        return yield* getConference(locale);
436	      },
437	    );
438	
439	    const getTranslations = Effect.fn('Content.getTranslations')(function* (
440	      locale: Locale,
441	    ) {
442	      assertValidLocale(locale);
443	      const content = yield* getSiteContent();
444	      return content.translations[locale];
445	    });
446	
447	    const getTeam = Effect.fn('Content.getTeam')(function* () {
448	      const content = yield* getSiteContent();
449	      return {
450	        team: content.team.map(toTeamMember),
451	        board: [...content.board],
452	      };
453	    });
454	
455	    // Arm the next public read to re-fetch the bucket so a publish is visible
456	    // immediately, with no redeploy and without waiting out the TTL (D3). This
457	    // is the built-in cache's `invalidate`: it expires the cached document and
458	    // clears the stored result, so the next `getSiteContent` recomputes
459	    // `fetchDocument`. (`make-operations-idempotent`: busting an already-empty
460	    // or already-expired cache is a harmless no-op.) The built-in does NOT
461	    // pre-empt an in-flight refresh: a publish landing during one is masked
462	    // because that refresh re-arms the TTL with its pre-publish document, so
463	    // the stale window measured from the publish is `(the refresh's remaining
464	    // bucket-read duration) + one TTL`, not ≤ one TTL. That documented window
465	    // is within D3's "visible on the next read after the window" contract
466	    // (see the `Content` doc above for the full mechanism).
467	    const bust = Effect.fn('Content.bust')(function* () {
468	      yield* invalidate;
469	    });
470	
471	    return Service.of({
472	      getSiteContent,
473	      getConference,
474	      getCurrentConference,
475	      getTranslations,
476	      getTeam,
477	      bust,
478	    });
479	  }),
480	);
