482	/**
483	 * The public read path's `Content`, with its `Storage` dependency pre-provided
484	 * as `Storage.layerOptional` (the never-fails-to-build storage, mirroring
485	 * opencode `packages/core/src/git.ts:347`). Only `Env` stays open, discharged
486	 * by the surrounding app-runtime merge. The admin write path provides `Storage`
487	 * standalone (a legit second consumer), so it is NOT wired here.
488	 */
489	export const defaultLayer = layer.pipe(Layer.provide(Storage.layerOptional));

