134	 * override, e.g. `t:en:main.newsletter.title` → `{ en: { 'main.newsletter.title':
135	 * '…' } }`. The key keeps its dots verbatim (it is a single map key, not a path).
136	 */
137	export const collectTranslations = (
138	  entries: Iterable<readonly [string, FormDataEntryValue]>,
139	): { readonly en: Record<string, string>; readonly fr: Record<string, string> } => {
140	  const en: Record<string, string> = {};
141	  const fr: Record<string, string> = {};
142	  for (const [name, value] of entries) {
143	    if (typeof value !== 'string' || !isTranslationField(name)) continue;
144	    const rest = name.slice(TRANSLATION_FIELD_PREFIX.length);
145	    const sep = rest.indexOf(':');
146	    if (sep === -1) continue;
147	    const locale = rest.slice(0, sep);
148	    const key = rest.slice(sep + 1);
149	    if (key === '') continue;
150	    if (locale === 'en') en[key] = value;
151	    else if (locale === 'fr') fr[key] = value;
152	  }
153	  return { en, fr };
154	};
