 64	type EncodedDocument = typeof SiteContent.Encoded;
 65	
 66	type ActionResult =
 67	  | { readonly ok: true }
 68	  | { readonly ok: false; readonly error: string; readonly issues: readonly string[] };
 69	
 70	/** Map a `DraftEditor` `IssueError` to the editor's JSON action response. */
 71	const issueResponse = (error: IssueError): Response =>
 72	  Response.json(
 73	    { ok: false, error: error.message, issues: error.issues },
 74	    { status: error.status },
 75	  );
