 77	export const loader = routeHandler(function* () {
 78	  const { request } = yield* ReactRouterContext;
 79	  const auth = yield* Auth.Service;
 80	  // 404 the whole area when disabled; the layout guard already redirected an
 81	  // unauthenticated visitor, but re-checking keeps this route safe on its own.
 82	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
 83	    Effect.catchTags({
 84	      'Auth.Disabled': () =>
 85	        Effect.fail(new Response('Not Found', { status: 404 })),
 86	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
 87	    }),
 88	  );
 89	
 90	  const editor = yield* DraftEditor.Service;
 91	  const env = yield* Env.Service;
 92	  const { content: document, source } = yield* editor.load(siteScope);
 93	  const encoded = yield* encodeDocument(document);
 94	
 95	  // The bucket is "configured" exactly when `Env.bucket` is present — the single
 96	  // source of truth (a bucket-less editor still renders so the admin can preview,
 97	  // but saving/publishing would fail, which we warn about up front).
 98	  const bucketConfigured = Option.isSome(env.bucket);
 99	
100	  return { document: encoded as EncodedDocument, source, bucketConfigured };
101	});
