103	export const action = routeAction(function* () {
104	  const { request } = yield* ReactRouterContext;
105	  const auth = yield* Auth.Service;
106	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
107	    Effect.catchTags({
108	      'Auth.Disabled': () =>
109	        Effect.fail(new Response('Not Found', { status: 404 })),
110	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
111	    }),
112	  );
113	
114	  const editor = yield* DraftEditor.Service;
115	  const storage = yield* Storage.Service;
116	  const form = yield* Effect.promise(() => request.formData());
117	  const intent = String(form.get('intent') ?? 'save-draft');
118	
119	  // ---- image upload --------------------------------------------------------
120	  // The route owns the FormData side: validate the file and store its raw bytes;
121	  // `DraftEditor.applyImageUpload` then rewrites the targeted `…key` field on the
122	  // draft so the new image survives a reload and a later publish.
123	  const uploadTarget = imageUploadTarget(intent);
124	  if (uploadTarget !== null) {
125	    const file = form.get('file');
126	    if (!(file instanceof File) || file.size === 0) {
127	      return Response.json(
128	        { ok: false, error: 'Choose an image before uploading.', issues: [] },
129	        { status: 400 },
130	      );
131	    }
132	    if (!isAcceptedImageType(file.type)) {
133	      return Response.json(
134	        {
135	          ok: false,
136	          error: 'Upload a JPEG, PNG, WebP, GIF, or AVIF image.',
137	          issues: [],
138	        },
139	        { status: 400 },
140	      );
141	    }
142	
143	    const now = yield* Clock.currentTimeMillis;
144	    const key = uploadedImageKey(uploadTarget, file.type, now);
145	    const bytes = new Uint8Array(yield* Effect.promise(() => file.arrayBuffer()));
146	
147	    const putExit = yield* Effect.exit(storage.put(key, bytes, file.type));
148	    if (putExit._tag === 'Failure') {
149	      return Response.json(
150	        {
151	          ok: false,
152	          error:
153	            'Image upload failed — is the bucket configured? ' +
154	            Cause.pretty(putExit.cause),
155	          issues: [],
156	        },
157	        { status: 502 },
158	      );
159	    }
160	
161	    const applied = yield* editor
162	      .applyImageUpload(siteScope, uploadTarget, key)
163	      .pipe(Effect.result);
164	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
165	    return redirect(
166	      `/admin/content?status=${encodeURIComponent(`Image uploaded: ${key}`)}`,
167	    );
168	  }
169	
170	  if (intent !== 'save-draft' && intent !== 'publish') {
171	    return Response.json(
172	      { ok: false, error: 'Unknown submit intent.', issues: [] },
173	      { status: 400 },
174	    );
175	  }
176	
177	  // ---- save / publish ------------------------------------------------------
178	  // Parse the form into ONE override: dotted-path fields via `assembleOverrides`,
179	  // plus the `t:<locale>:<key>` translation fields folded onto `translations`
180	  // (their keys carry dots, so they can't ride the dotted-path convention).
181	  // `DraftEditor.editDocument` merges it onto the current document, decodes at
182	  // the single boundary, and stores the draft.
183	  const override = deepMerge(assembleOverrides(form.entries()), {
184	    translations: collectTranslations(form.entries()),
185	  } as Json);
186	
187	  const edited = yield* editor
188	    .editDocument(siteScope, override)
189	    .pipe(Effect.result);
190	  if (edited._tag === 'Failure') return issueResponse(edited.failure);
191	
192	  if (intent === 'save-draft') {
193	    return redirect('/admin/content?status=Draft%20saved.');
194	  }
195	
196	  // publish: promote the just-saved draft to the live document, drop the draft,
197	  // and bust the read cache so the change is live on the next public read.
198	  const published = yield* editor.publish(siteScope).pipe(Effect.result);
199	  if (published._tag === 'Failure') return issueResponse(published.failure);
200	  return redirect(
201	    '/admin/content?status=Published.%20Live%20on%20the%20next%20page%20load.',
202	  );
203	});
