264	/**
265	 * A per-image uploader. It posts to this route's action independently of the
266	 * surrounding save/publish form via a `useFetcher` — *not* a nested `<form>`
267	 * (HTML forbids nesting forms, and the editor's main `<Form>` wraps every
268	 * section, so rendering an inner form here would let SSR/hydration close or drop
269	 * either form's tags and silently break submission). Instead the uploader is a
270	 * plain element tree; the "Upload" button hands a one-off `FormData` (carrying
271	 * `intent=upload:<keyPath>` and the chosen `file`) to `fetcher.submit` as
272	 * multipart. The action stores the bytes and rewrites that key on the draft,
273	 * then redirects, which revalidates this route's loader so the new key shows.
274	 */
275	function ImageUpload({
276	  keyPath,
277	  currentKey,
278	}: {
279	  readonly keyPath: string;
280	  readonly currentKey: string;
281	}) {
282	  const fetcher = useFetcher<ActionResult>();
283	  const fileRef = useRef<HTMLInputElement>(null);
284	  const uploading = fetcher.state !== 'idle';
285	
286	  const upload = () => {
287	    const file = fileRef.current?.files?.[0];
288	    if (!file) return;
289	    const data = new FormData();
290	    data.set('intent', `upload:${keyPath}`);
291	    data.set('file', file);
292	    void fetcher.submit(data, { method: 'post', encType: 'multipart/form-data' });
293	  };
294	
295	  return (
296	    <div className="space-y-1 rounded-md border border-dashed border-neutral-300 p-2">
297	      <p className="text-xs text-neutral-600">
298	        Current: <code className="text-neutral-800">{currentKey}</code>
299	      </p>
300	      <div className="flex items-center gap-2">
301	        <input
302	          ref={fileRef}
303	          type="file"
304	          accept="image/jpeg,image/png,image/webp,image/gif,image/avif"
305	          className="text-xs"
306	        />
307	        <button
308	          type="button"
309	          onClick={upload}
310	          disabled={uploading}
311	          className="inline-flex min-h-9 cursor-pointer items-center rounded-md border border-neutral-300 px-3 text-xs font-medium hover:bg-neutral-100 disabled:opacity-50"
312	        >
313	          {uploading ? 'Uploading…' : 'Upload'}
314	        </button>
315	      </div>
316	      {fetcher.data && !fetcher.data.ok && (
317	        <p className="text-xs text-rose-700">{fetcher.data.error}</p>
318	      )}
319	    </div>
320	  );
