 95	type ListClient = {
 96	  readonly list: (input: {
 97	    readonly prefix?: string;
 98	    readonly continuationToken?: string;
 99	  }) => Promise<{
100	    readonly contents?: readonly {
101	      readonly key: string;
102	      readonly size?: number;
103	      readonly lastModified?: string;
104	    }[];
105	    readonly nextContinuationToken?: string;
106	  }>;
107	};
108	
109	const epoch = (): Date => DateTime.toDateUtc(DateTime.makeUnsafe(0));
110	
111	const listStoredObjects = Effect.fnUntraced(function* (
112	  client: ListClient,
113	  prefix: string | undefined,
114	) {
115	  const objects: ListedObject[] = [];
116	  let continuationToken: string | undefined;
117	  do {
118	    const page = yield* Effect.tryPromise({
119	      try: () => client.list({ prefix, continuationToken }),
120	      catch: (e) => new StorageError({ key: prefix ?? '', op: 'list', cause: e }),
121	    });
122	    for (const item of page.contents ?? []) {
123	      objects.push({
124	        key: item.key,
125	        size: item.size ?? 0,
126	        lastModified:
127	          item.lastModified !== undefined
128	            ? DateTime.toDateUtc(DateTime.makeUnsafe(item.lastModified))
129	            : epoch(),
130	      });
131	    }
132	    continuationToken = page.nextContinuationToken;
133	  } while (continuationToken !== undefined);
134	  return objects;
135	});
