154	/**
155	 * The bucket-backed `Storage`, reading its config off `Env` (opencode's
156	 * module-level `export const layer`, `packages/core/src/git.ts:79`). When
157	 * `Env.bucket` is absent it fails with `StorageUnconfigured`; callers that want
158	 * the degraded path compose `layerOptional` instead of holding a half-built
159	 * instance (`make-impossible-states-unrepresentable`).
160	 */
161	export const layer = Layer.effect(
162	  Service,
163	  Effect.gen(function* () {
164	    const env = yield* Env.Service;
165	
166	    if (Option.isNone(env.bucket)) {
167	      return yield* new StorageUnconfigured();
168	    }
169	
170	    const config = env.bucket.value;
171	    const client = new Bun.S3Client({
172	      endpoint: config.endpoint,
173	      accessKeyId: Redacted.value(config.accessKeyId),
174	      secretAccessKey: Redacted.value(config.secretAccessKey),
175	      bucket: config.bucket,
176	      region: config.region,
177	    });
178	
179	    const get = Effect.fn('Storage.get')(function* (key: string) {
180	      const file = client.file(key);
181	      const stat = yield* Effect.tryPromise({
182	        try: () => file.stat(),
183	        catch: (e) =>
184	          isNoSuchKey(e)
185	            ? new NotFound({ key })
186	            : new StorageError({ key, op: 'get', cause: e }),
187	      });
188	      return {
189	        stream: file.stream(),
190	        contentType: stat.type === '' ? 'application/octet-stream' : stat.type,
191	        size: stat.size,
192	      };
193	    });
194	
195	    const put = Effect.fn('Storage.put')(function* (
196	      key: string,
197	      body: Uint8Array | string,
198	      contentType: string,
199	    ) {
200	      yield* Effect.tryPromise({
201	        try: () => client.write(key, body, { type: contentType }),
202	        catch: (e) => new StorageError({ key, op: 'put', cause: e }),
203	      });
204	    });
205	
206	    const head = Effect.fn('Storage.head')(function* (key: string) {
207	      const file = client.file(key);
208	      const exists = yield* Effect.tryPromise({
209	        try: () => file.exists(),
210	        catch: (e) => new StorageError({ key, op: 'head', cause: e }),
211	      });
212	      if (!exists) return Option.none<ObjectHead>();
213	      const stat = yield* Effect.tryPromise({
214	        try: () => file.stat(),
215	        catch: (e) => new StorageError({ key, op: 'head', cause: e }),
216	      });
217	      return Option.some<ObjectHead>({
218	        size: stat.size,
219	        contentType: stat.type === '' ? 'application/octet-stream' : stat.type,
220	        lastModified: stat.lastModified,
221	        etag: stat.etag,
222	      });
223	    });
224	
225	    const list = Effect.fn('Storage.list')(function* (prefix?: string) {
226	      return yield* listStoredObjects(client, prefix);
227	    });
228	
229	    const del = Effect.fn('Storage.delete')(function* (key: string) {
230	      yield* Effect.tryPromise({
231	        try: () => client.delete(key),
232	        catch: (e) => new StorageError({ key, op: 'delete', cause: e }),
233	      });
234	    });
235	
236	    return Service.of({ get, put, head, list, delete: del });
237	  }),
238	);
