240	/**
241	 * A `Storage` that never fails to *build*: it uses the real bucket-backed
242	 * `layer` when a bucket is configured, and a **disabled** in-bucket-less
243	 * instance otherwise (where every read reports `NotFound` and every write
244	 * fails `StorageError`). This is the layer the always-on `Content` service
245	 * (C3) composes: the CMS is optional everywhere, so `Storage` must be present
246	 * in the application context even without a bucket — callers then degrade to
247	 * bundled defaults on the `NotFound`, rather than the whole runtime failing to
248	 * build on `StorageUnconfigured` (`make-impossible-states-unrepresentable`,
249	 * D3). The admin write path (C4/C5) is only reachable when a bucket *is*
250	 * configured, so the disabled writes are unreachable there.
251	 */
252	export const layerOptional = layer.pipe(
253	  Layer.catchCause(() =>
254	    Layer.succeed(
255	      Service,
256	      Service.of({
257	        get: (key) => Effect.fail(new NotFound({ key })),
258	        put: (key) =>
259	          Effect.fail(
260	            new StorageError({
261	              key,
262	              op: 'put',
263	              cause: new Error('storage unconfigured'),
264	            }),
265	          ),
266	        head: () => Effect.succeed(Option.none()),
267	        list: () => Effect.succeed([]),
268	        delete: () => Effect.void,
269	      }),
270	    ),
271	  ),
272	);
