274	/**
275	 * The self-contained, never-fails-to-build `Storage` (opencode's
276	 * `export const defaultLayer`, `packages/core/src/git.ts:347`): `layerOptional`
277	 * with its `Env` dependency pre-provided. The standalone consumers that need a
278	 * `Storage` without separately wiring `Env` — the `/images/*` route in
279	 * `server.ts` and the `/admin` write path — provide this directly. (`Content`
280	 * composes `layerOptional` on its own `defaultLayer` instead, sharing `Env`
281	 * with the rest of the app runtime.)
282	 */
283	export const defaultLayer = layerOptional.pipe(Layer.provide(Env.defaultLayer));

